import { sql } from "drizzle-orm";

import { COLLECTIONS } from "@/lib/data/collections";
import { DEPARTMENTS } from "@/lib/data/departments";
import { EXTENSIONS } from "@/lib/data/extensions";
import { db } from "@/lib/db/client";
import {
  departments,
  extensions,
  extensionTags,
  organizations,
  tags,
} from "@/lib/db/schema";
import { TAG_LABELS } from "@/lib/tags";
import type { Department } from "@/types";

// Single-tenant default for v1; multi-org UI lives behind this for later.
const ORG_ID = "default";

interface FlatDept {
  id: string;
  orgId: string;
  parentId: string | null;
  name: string;
  nameZh: string;
  pathDepth: number;
}

function flattenDepts(
  list: Department[],
  depth = 0,
  parentId: string | null = null,
  out: FlatDept[] = [],
): FlatDept[] {
  for (const d of list) {
    out.push({
      id: d.id,
      orgId: ORG_ID,
      parentId,
      name: d.name,
      nameZh: d.nameZh,
      pathDepth: depth,
    });
    if (d.children) flattenDepts(d.children, depth + 1, d.id, out);
  }
  return out;
}

function slugify(name: string): string {
  return name
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

const CATEGORY_LABELS = {
  skills: "skill",
  mcp: "MCP server",
  slash: "slash command",
  plugins: "plugin",
} as const;

/**
 * Placeholder README content. Real READMEs will arrive via the upload wizard
 * (Phase 10) once the manifest spec is wired up.
 */
function generateReadme(ext: (typeof EXTENSIONS)[number]): string {
  const kind = CATEGORY_LABELS[ext.category];
  const installCmd =
    ext.category === "slash"
      ? `agentcenter install ${slugify(ext.name)}`
      : `agentcenter install ${slugify(ext.name)}`;
  return `# ${ext.name}

${ext.desc}

## Overview

${ext.name} is a ${kind} published by **${ext.author}**. It plugs into your
agent runtime so you can ${ext.desc.toLowerCase().replace(/\.$/, "")} without
hand-rolling integrations.

## Install

\`\`\`bash
${installCmd}
\`\`\`

After installing, restart your agent to pick up the new ${kind}.

## Compatibility

- **Claude** — supported on the latest agent runtimes
- **Other agents** — install paths can be customized via \`agentcenter config\`

## Tags

${ext.tags.map((t) => `\`${t}\``).join(" · ")}
`;
}

async function main() {
  console.log("seed: starting");

  // Idempotent wipe of catalog data. CASCADE follows FKs through the whole
  // org→dept→extension→junction graph. Leaves users/sessions/tags untouched
  // for orgs; we then separately wipe tags.
  console.log("seed: truncating catalog tables");
  await db.execute(
    sql`TRUNCATE TABLE ${organizations}, ${tags} RESTART IDENTITY CASCADE`,
  );

  console.log("seed: inserting org");
  await db.insert(organizations).values({
    id: ORG_ID,
    slug: "default",
    name: "Default Organization",
    nameZh: "默认组织",
  });

  const flatDepts = flattenDepts(DEPARTMENTS);
  console.log(`seed: inserting ${flatDepts.length} departments`);
  await db.insert(departments).values(flatDepts);

  const tagRows = Object.entries(TAG_LABELS).map(([id, label]) => ({
    id,
    labelEn: label.en,
    labelZh: label.zh,
  }));
  console.log(`seed: inserting ${tagRows.length} tags`);
  await db.insert(tags).values(tagRows);

  const extRows = EXTENSIONS.map((e) => ({
    id: `ext-${e.id}`,
    slug: slugify(e.name),
    category: e.category,
    badge: e.badge ?? null,
    scope: e.scope,
    funcCat: e.funcCat,
    subCat: e.subCat,
    publisherUserId: null,
    ownerOrgId: ORG_ID,
    deptId: e.dept,
    iconEmoji: e.icon,
    iconColor: e.color,
    visibility: "published" as const,
    name: e.name,
    nameZh: e.nameZh,
    description: e.desc,
    descriptionZh: e.descZh,

import { z } from "zod";

// Slug shape, exported so client-side form validators don't redefine it.
export const SLUG_PATTERN = /^[a-z0-9]+(?:-[a-z0-9]+)*$/;
export const SEMVER_PATTERN = /^\d+\.\d+\.\d+$/;

// Single source of truth for what makes an extension manifest valid.
// Mirrors `docs/manifest-spec.md`. Form and bundle schemas below derive
// from this core; nothing should redefine these constraints elsewhere.
export const ExtensionManifestCore = z.object({
  slug: z
    .string()
    .min(3)
    .max(64)
    .regex(SLUG_PATTERN, "Lowercase letters, numbers and hyphens only"),
  name: z.string().min(2).max(80),
  nameZh: z.string().max(80).optional(),
  version: z.string().regex(SEMVER_PATTERN, "Must be semver (e.g. 1.0.0)"),
  category: z.enum(["skills", "mcp", "slash", "plugins"]),
  scope: z.enum(["personal", "org", "enterprise"]),
  funcCat: z.enum(["workTask", "business", "tools"]),
  subCat: z.string().min(1).max(60),
  l2: z.string().max(60).optional(),
  description: z.string().min(1).max(280),
  descriptionZh: z.string().max(280).optional(),
  tagline: z.string().max(120).optional(),
});

// Form: every core field plus the UI-only extras the publish wizard collects.
export const ManifestFormSchema = ExtensionManifestCore.extend({
  tagIds: z.array(z.string()).max(8),
  deptId: z.string().optional(),
  homepageUrl: z.string().url().optional().or(z.literal("")),
  repoUrl: z.string().url().optional().or(z.literal("")),
  licenseSpdx: z.string().max(40).optional(),
});

export type ManifestFormValues = z.infer<typeof ManifestFormSchema>;

// Bundle: same fields, lifted into the [extension] / [categorization] TOML
// sections defined in docs/manifest-spec.md.
export const BundleManifestSchema = z.object({
  extension: ExtensionManifestCore.pick({
    slug: true,
    name: true,
    nameZh: true,
    version: true,
    category: true,
    scope: true,
    description: true,
    descriptionZh: true,
    tagline: true,
  }),
  categorization: ExtensionManifestCore.pick({
    funcCat: true,
    subCat: true,
    l2: true,
  }),
});

export type BundleManifest = z.infer<typeof BundleManifestSchema>;

